content:
{
  "sentences": [
    {
      "text": "你正在做什麼？",
      "pinyin": "Nǐ zhèngzài zuò shénme?",
      "pinyin_numeric": "ni3 zheng4zai4 zuo4 shen2me0",
      "translation_en": "What are you doing right now?",
      "translation_ko": "지금 무엇을 하고 계세요?"
    },
    {
      "text": "我正在上網看新聞。",
      "pinyin": "Wǒ zhèngzài shàngwǎng kàn xīnwén.",
      "pinyin_numeric": "wo3 zheng4zai4 shang4wang3 kan4 xin1wen2",
      "translation_en": "I am browsing the internet and reading news.",
      "translation_ko": "저는 지금 인터넷으로 뉴스를 보고 있어요."
    },
    {
      "text": "他正在開會，不方便講電話。",
      "pinyin": "Tā zhèngzài kāihuì, bù fāngbiàn jiǎng diànhuà.",
      "pinyin_numeric": "ta1 zheng4zai4 kai1hui4, bu4 fang1bian4 jiang3 dian4hua4",
      "translation_en": "He is in a meeting and not available to talk on the phone.",
      "translation_ko": "그는 지금 회의 중이라 전화를 받기 어려워요."
    },
    {
      "text": "她正在寫功課，等一下再回你訊息。",
      "pinyin": "Tā zhèngzài xiě gōngkè, děng yīxià zài huí nǐ xùnxí.",
      "pinyin_numeric": "ta1 zheng4zai4 xie3 gong1ke4, deng3 yi1xia4 zai4 hui2 ni3 xun4xi2",
      "translation_en": "She is doing homework and will reply to your message later.",
      "translation_ko": "그녀는 지금 숙제를 하고 있어서, 잠시 후에 답장할게요."
    },
    {
      "text": "我們正在準備明天的報告。",
      "pinyin": "Wǒmen zhèngzài zhǔnbèi míngtiān de bàogào.",
      "pinyin_numeric": "wo3men0 zheng4zai4 zhun3bei4 ming2tian1 de0 bao4gao4",
      "translation_en": "We are preparing for tomorrow's presentation.",
      "translation_ko": "저희는 내일 발표를 준비하고 있어요."
    },
    {
      "text": "你正在滑手機嗎？",
      "pinyin": "Nǐ zhèngzài huá shǒujī ma?",
      "pinyin_numeric": "ni3 zheng4zai4 hua2 shou3ji1 ma0",
      "translation_en": "Are you scrolling on your phone?",
      "translation_ko": "지금 핸드폰을 보고 계세요?"
    },
    {
      "text": "我現在正在忙，等一下再跟你說。",
      "pinyin": "Wǒ xiànzài zhèngzài máng, děng yīxià zài gēn nǐ shuō.",
      "pinyin_numeric": "wo3 xian4zai4 zheng4zai4 mang2, deng3 yi1xia4 zai4 gen1 ni3 shuo1",
      "translation_en": "I am busy right now; I'll talk to you later.",
      "translation_ko": "지금 바빠서, 잠시 후에 말할게요."
    },
    {
      "text": "他正在傳訊息給朋友。",
      "pinyin": "Tā zhèngzài chuán xùnxí gěi péngyǒu.",
      "pinyin_numeric": "ta1 zheng4zai4 chuan2 xun4xi2 gei3 peng2you3",
      "translation_en": "He is sending a message to his friend.",
      "translation_ko": "그는 지금 친구에게 메시지를 보내고 있어요."
    },
    {
      "text": "不好意思打擾，你正在上課嗎？",
      "pinyin": "Bù hǎoyìsi dǎrǎo, nǐ zhèngzài shàngkè ma?",
      "pinyin_numeric": "bu4 hao3yi4si0 da3rao3, ni3 zheng4zai4 shang4ke4 ma0",
      "translation_en": "Sorry to bother you, are you in class right now?",
      "translation_ko": "방해해서 죄송한데, 지금 수업 중이세요?"
    },
    {
      "text": "她正在看書，不急，慢慢來。",
      "pinyin": "Tā zhèngzài kàn shū, bù jí, mànmàn lái.",
      "pinyin_numeric": "ta1 zheng4zai4 kan4 shu1, bu4 ji2, man4man4 lai2",
      "translation_en": "She is reading a book; no rush, take your time.",
      "translation_ko": "그녀는 지금 책을 읽고 있어요. 서두르지 마세요, 천천히 하세요."
    }
  ]
}
